export const getGetServicesPopularityUrl = () => {




  return `/api/dashboard/services-popularity`
}

/**
 * @summary Get service categories popularity
 */
export const getServicesPopularity = async ( options?: RequestInit): Promise<ServicePopularity[]> => {

  return customFetch<ServicePopularity[]>(getGetServicesPopularityUrl(),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetServicesPopularityQueryKey = () => {
    return [
    `/api/dashboard/services-popularity`
    ] as const;
    }


export const getGetServicesPopularityQueryOptions = <TData = Awaited<ReturnType<typeof getServicesPopularity>>, TError = ErrorType<unknown>>( options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getServicesPopularity>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getGetServicesPopularityQueryKey();



    const queryFn: QueryFunction<Awaited<ReturnType<typeof getServicesPopularity>>> = ({ signal }) => getServicesPopularity({ signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof getServicesPopularity>>, TError, TData> & { queryKey: QueryKey }
}

